/**
 * @typedef {Number} types
 */

/**
 * Enum for data types.
 * @readonly
 * @enum {types}
 */
const types = Object.freeze({
    STRING: 0,
    NUMBER: 1
});

/**
 * Reads a datpartout file.
 * @param {ArrayBuffer} fileBuffer The data.
 */
const DATPARTOUT = function (fileBuffer) {

    this.dataURI = "";

    this.header = {
        signature: "PARTOUT(4.0)RESOURCE", // [21 bytes] zero-terminated string, signature: "PARTOUT(4.0)RESOURCE"
        appName: "",                       // [50 bytes] zero-terminated string, application name
        description: "",                   // [100 bytes] zero-terminated string, file description
        fileSize: 0,                       // [4 bytes] file size, integer - total size of this file
        nGroups: 0,                        // [2 bytes] nGroups, integer - number of item groups in this file
        tableSize: 0,                      // [2 bytes] unknown1 (seemingly random, maybe checksum of some kind)
        fullWidth: 0                       // [4 bytes] unknown2 (some small integer, seen values 0 through 25)
    };

    this.groups = [];

    let filePointer = 21;
    this.header.appName = readString(50);
    this.header.description = readString(100);
    this.header.fileSize = readNumber(4);
    this.header.nGroups = readNumber(2);
    this.header.tableSize = readNumber(2);
    this.header.fullWidth = readNumber(4);

    for (let groupID = 0; groupID < this.header.nGroups; groupID++) {
        
        this.groups[groupID] = {
            nEntries: readNumber(1),
            entries: []
        };

        for (let entryID = 0; entryID < this.groups[groupID].nEntries; entryID++) {

            const entry = {
                type: readNumber(1)
            };

            switch (entry.type) {
                case 0: // RESOURCE IDENTIFIER
                    entry.data = readNumber(2);
                    break;
                case 1: // IMAGE
                    entry.dataLength = readNumber(4);
                    entry.tableSize = readNumber(1);
                    entry.width = readNumber(2);
                    entry.height = readNumber(2);
                    entry.fullWidth = readNumber(2);
                    entry.unk3 = readNumber(2);
                    entry.imageSize = readNumber(4);
                    entry.unk4 = readNumber(1);

                    if (entry.unk4 === 5) {
                        entry.lines = [];
                        for (let i = 0; readNumber(2, false) !== 0xFFFF; i++) {
                            entry.lines[i] = {
                                offset: readNumber(2),
                                lineSize: readNumber(2),
                                pixels: [],
                            };

                            for (let j = 0; j < entry.lines[i].lineSize; j++) {
                                entry.lines[i].pixels[j] = {
                                    dist: readNumber(2),
                                    color: readNumber(1)
                                };
                            }
                        }
                        entry.endboi = readNumber(2);
                    } else {
                        entry.padding = Math.ceil(-((entry.height * entry.width - entry.imageSize) / entry.height));
                        entry.data = readNumber(entry.imageSize);
                    }

                    break;
                case 5: // PALETTE
                    entry.dataLength = readNumber(4);
                    entry.data = {
                        colors: []
                    };
                    for (let color = 0; color < entry.dataLength / 4; color++) {
                        entry.data.colors[color] = {};
                        entry.data.colors[color].b = readNumber(1);
                        entry.data.colors[color].g = readNumber(1);
                        entry.data.colors[color].r = readNumber(1);
                        entry.data.colors[color].a = readNumber(1);
                    }
                    break;
                case 3: // TEXT
                case 9: // TEXT2
                    entry.dataLength = readNumber(4);
                    entry.data = readNumber(entry.dataLength, 0);
                    break;
                case 12: // Z BUFFER DATA
                    entry.dataLength = readNumber(4);
                    entry.unk1 = readNumber(1);
                    entry.width = readNumber(2);
                    entry.height = readNumber(2);
                    entry.fullWidth = readNumber(2);
                    entry.unk3 = readNumber(4);
                    entry.unk4 = readNumber(2);
                    entry.unk5 = readNumber(2);
                    entry.data = [];
                    for (let i = 0; i < entry.fullWidth * entry.height; i++) {
                        entry.data.push(readNumber(2));
                    }
                    break;
                default:
                    entry.dataLength = readNumber(4);
                    entry.data = readNumber(entry.dataLength);
                    break;
            }
            
            this.groups[groupID].entries[entryID] = entry;
        }
    }

    /**
     * Read a number from the file.
     * @param {number} nBytes Number of bytes to read.
     * @param {Boolean} advancePointer Whether to advance the file pointer or not.
     * @returns {*} The data.
     */
    function readNumber(nBytes, advancePointer = true) {
        const data = new Uint8Array(fileBuffer.slice(filePointer, filePointer + nBytes));

        if (advancePointer) {
            filePointer += nBytes;
        }

        return bytesToNumber(data);
    }

    /**
     * Read a string from the file.
     * @param {number} nBytes Number of bytes to read.
     * @param {Boolean} advancePointer Whether to advance the file pointer or not.
     * @returns {*} The data.
     */
    function readString(nBytes, advancePointer = true) {
        const data = new Uint8Array(fileBuffer.slice(filePointer, filePointer + nBytes));

        if (advancePointer) {
            filePointer += nBytes;
        }

        return bytesToString(data);
    }
};

/**
 * @param {Uint8Array} bytes
 * @return {Number}
 */
function bytesToNumber(bytes) {
    let result = 0;

    for (let byte = 0; byte < bytes.length; byte++)
        result += bytes[byte] << byte * 8;

    return result;
}

/**
 * @param {Array<Number>} charCodes
 * @return {String}
 */
function bytesToString(charCodes) {
    let result = "";
    for (let i = 0; i < charCodes.length; i++)
        result += String.fromCharCode(charCodes[i]);
    return result;
}

/**
 * Turns a number into 4 bytes.
 * @param {Number} n The number.
 * @returns {Uint8Array} The bytes.
 */
function uint32ToArray(n) {
    return [n & 0xFF, (n >> 8) & 0xFF, (n >> 16) & 0xFF, (n >> 24) & 0xFF];
}

/**
 * Turns a number into 2 bytes.
 * @param {Number} n The number.
 * @returns {Uint8Array} The bytes.
 */
function uint16ToArray(n) {
    return [n & 0xFF, (n >> 8) & 0xFF];
}

function zeroArray(length) {
    const array = [];
    for (let i = 0; i < length; i++)
        array.push(0);
    return array;
}

function u8toNormal(u8) {
    const array = [];
    for (let i = 0; i < u8.length; i++)
        array.push(u8[i]);
    return array;
}

/**
 * Turns a string into an array of char codes.
 * @param {String} s The string.
 * @returns {Array<Number>} The char codes.
 */
function getCharCodes(s) {
    const result = [];
    for (let l = 0; l < s.length; l++) {
        result.push(s.charCodeAt(l));
    }
    return result;
}

export { DATPARTOUT };
